var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"<color=#ffd34c>며칠 뒤</color>","JPN":"<color=#ffd34c>数日後</color>","ENG":"<color=#ffd34c>A few days later</color>","TWN":"<color=#ffd34c>幾天後</color>","SCN":"<color=#ffd34c>几天后</color>","DEU":"<color=#ffd34c>A few days later</color>","FRA":"<color=#ffd34c>A few days later</color>"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"하늘에 계신 우리 아버지…….","JPN":"天にまします我らの父よ……","ENG":"Our Father, Who art in heaven...","TWN":"天上的父親……"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"아버지 이름이… 거룩히 빛나시며…….","JPN":"願わくは……御名の尊まれんことを……","ENG":"Hallowed be... Thy name...","TWN":"父親的名字……神聖地閃耀著……"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"하암~ 지겨워서 돌아버리겠어, 아주.","JPN":"ふああ。もう、うんざりだよ、まったく。","ENG":"*Yawn* I'm going to die of boredom.","TWN":"唉～超無聊的，討厭。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"망할 꼰대, 대체 내가 뭘 잘못했다고 이러는 거야?","JPN":"クソばばあ、アタシが何したって言うんだよ。","ENG":"That stupid snob. What the heck did I even do wrong?","TWN":"該死的四眼姊姊，我到底做錯了什麼？"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"이깟 기도문이 밥이라도 떠먹여 준대?","JPN":"こんな祈りが腹を満たしてくれるわけでもないのに。","ENG":"It's not like this prayer is going to keep food on the table for me!","TWN":"這破祈祈禱文能當飯吃嗎？"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"……좋아. 아무도 없지?","JPN":"……よし。誰もいないよね？","ENG":"...Okay. No one's around, right?","TWN":"……很好，沒人在吧？"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"후후, 그럼 오늘은 이걸로 바이올런스를 충전해 볼까나?","JPN":"ふふ、さて、今日はこれでバイオレンスをチャージするか？","ENG":"Hehe, I guess this'll do to charge my violence...","TWN":"呵呵，那今天就用這個來補充暴力值吧？"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_LAUGH"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"넬슨이 코 잘 때, 슬쩍한 이거… 스마트폰이라고 했나?","JPN":"ネルソンが寝てた時にこっそり持ってきたこれ……スマートフォンだっけ？","ENG":"This thing I swiped from Nelson while she was fast asleep... I think it is called a smartphone…","TWN":"趁著尼爾森睡覺時偷偷拿的這個……是叫智慧手機嗎？"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"이런 손바닥 만한 전화기로 비디오테이프 없이 영화를 볼 수 있다니, 세상 참 좋아졌다니까.","JPN":"こんな小さな電話機でビデオテープもないのに映画を見れるなんて、本当にいい世の中になったね。","ENG":"I can't believe this tiny device allows me to watch movies even without a tape. The world has gotten so convenient these days.","TWN":"居然能用這麼小的東西看電影，還不用錄影帶，真是太方便了。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"어디 보자…….","JPN":"どれどれ……","ENG":"Let's see here...","TWN":"讓我看看……"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"CAKE_CHOCOLAT_NPC_QM","text":{"KOREA":"꼬맹이 시스터 주제에 잘도 애늙은이 같은 소리를 하는군요.","JPN":"チビシスターの分際で、そんな年寄りみたいなことを言って。","ENG":"For a little Sister, you talk like an old soul.","TWN":"明明是個小丫頭，怎麼用字這麼老氣。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"윽, 이 목소리는 설마……?","JPN":"うっ、この声はまさか……？","ENG":"Ngh? That voice...!","TWN":"嗯，這聲音難道是……？"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"하지만 기꺼이 정정해드리죠. 시스터 루퍼.","JPN":"ですが、喜んで訂正いたします、シスター・ルーパー。","ENG":"I would be more than happy to rephrase, Sister Looper.","TWN":"我要更正一下，洛珀姊妹。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"스마트폰이라면 당신이 태어나기 전부터 있었답니다. 단지, 당신이 몰랐을 뿐이겠죠.","JPN":"スマートフォンならあなたが生まれる前からあったものです。ただ、あなたが知らなかっただけです。","ENG":"Smartphones existed before you were born. You merely didn't know about them.","TWN":"智慧手機在你出生之前就已經存在了，只是你不知道而已。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"언제부터 거기 있었어, 꼰대. 여태까지 날 감시한 거야?","JPN":"いつからそこにいたんだよ、ばばあ。今までアタシを監視してたの？","ENG":"How long have you been there, Specky Snob? Are you spying on me?","TWN":"你從什麼時候開始在那裡的，四眼姊姊，你一直在監視我嗎？"},"stage":{"bg":"ROOM_03","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"물론이죠. 말씀드렸을 텐데요. 당신을 조신한 시스터로 만들어드리겠다고.","JPN":"もちろんです。言ったはずですよ。あなたを慎ましいシスターにしてあげると。","ENG":"Of course. Did I not say that I will turn you into a respectable Sister?","TWN":"當然了，我不是已經告訴過你，我會幫助你成為一位合格的修女。"},"stage":{"bg":"ROOM_03","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"당신의 일거수일투족 정도는 전부 파악하고 있습니다.","JPN":"あなたの行動くらい、すべて把握しています。","ENG":"I have figured out your every move.","TWN":"你的每一個舉動我都瞭若指掌。"},"stage":{"bg":"ROOM_03","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"쳇, 있으면 있다고 말이라도 하든가. 기분 나쁘게.","JPN":"ちっ、いるならいるって言ってよね。気持ち悪い。","ENG":"Tch! Well, you should say something if you're there. Creep.","TWN":"嘖，在的話就出個聲嘛，真讓人不爽。"},"stage":{"bg":"ROOM_03","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_HATE"}}}},{"id":"L33_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"관음증이라도 있어? 취향 한번 고약하구만.","JPN":"のぞき癖でもあるの？　いい趣味してるね。","ENG":"Do you like spying on people? What a terrible hobby.","TWN":"你有偷窺癖嗎？什麼怪癖。"},"stage":{"bg":"ROOM_03","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"이상하군요. 취향이 고약한 건 제가 아니라 당신일 텐데요.","JPN":"おかしいですね。趣味が悪いのは私ではなくてあなたのはずです。","ENG":"How odd of you to say that when you are the one with the horrific hobby.","TWN":"真奇怪，有怪癖的應該不是我，而是你吧。"},"stage":{"bg":"ROOM_03","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"앗, 무슨 짓이야. 돌려줘.","JPN":"ちょっと、何してるんだよ？　返してよ。","ENG":"Huh? Hey, what are you doing? Give it back.","TWN":"啊，你幹什麼！還給我。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"이 불경한 영상물은 제가 가져가도록 하겠습니다.","JPN":"この不敬な映像は私が回収します。","ENG":"I will confiscate this blasphemous video.","TWN":"這部褻瀆神明的影片就由我來收下吧。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};